            aWandererK = aWandererK + ((RotL64(aPrevious, 60U) + aOrbiterH) + RotL64(aOrbiterJ, 19U));
            aWandererF = aWandererF ^ ((RotL64(aScatter, 43U) + RotL64(aOrbiterH, 5U)) + aOrbiterB);
            aWandererH = aWandererH + (((RotL64(aCross, 3U) + RotL64(aOrbiterA, 23U)) + aOrbiterE) + RotL64(aCarry, 53U));
