            aOrbiterE = RotL64((aOrbiterE * 0xB07BA9653BBBE291ULL), 23U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterF) + 0xFC86C223019F1A10ULL) + aPhaseFOrbiterUpdateSaltA[((aIndex + 23U)) & 31];
            aOrbiterD = (aOrbiterD ^ aOrbiterC) ^ 0x979EB014DEE56E3CULL;
