            aWandererC = aWandererC ^ (((RotL64(aPrevious, 47U) + RotL64(aOrbiterF, 5U)) + aOrbiterG) + aPhaseCWandererUpdateSaltB[(((31U - aIndex) + 5U)) & 31]);
