            aOrbiterI = (aOrbiterI + aOrbiterH) + 0x80D78610276522ADULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterI) ^ 0xB14D2F2E19D781D1ULL) ^ aPhaseGOrbiterUpdateSaltE[((aIndex + 29U)) & 31];
            aOrbiterE = RotL64((aOrbiterE * 0xB46E9EF0C309A689ULL), 51U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterJ) + 0x6B2541C284C1EA56ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterE) ^ 0xB51E3471C67663C3ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x9CE0F1D0F1CF2EAFULL), 27U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 0xE2BF359F5C63CBA6ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 0x4BC38C2B7391B1CBULL;
            aOrbiterD = RotL64((aOrbiterD * 0xB3DB1B1720A97283ULL), 41U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterG) + 0x6BE96C5C6529A576ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterB) ^ 0x3861FD29D42FA875ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x95ECC2AFD50E9BA1ULL), 37U);
