            aWandererE = aWandererE ^ ((RotL64(aPrevious, 35U) + aOrbiterE) + RotL64(aOrbiterJ, 3U));
            aWandererD = aWandererD + (((RotL64(aCross, 60U) + aOrbiterJ) + RotL64(aOrbiterC, 23U)) + RotL64(aCarry, 37U));
