            aOrbiterJ = (((aWandererD + RotL64(aCross, 51U)) + RotL64(aCarry, 43U)) + 0x44BB09AF62640A97ULL) + aPhaseGOrbiterAssignSaltF[(((31U - aIndex) + 28U)) & 31];
